namespace DocSummary.Models;

public class SummarizeRequest
{
    public required string DocumentText { get; set; }
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalLength { get; set; }
    public int SummaryLength { get; set; }
}

namespace DocSummary.Services;

public interface IDocumentSummarizer
{
    string Summarize(string documentText, int maxSentences);
}

public class DocumentSummarizer : IDocumentSummarizer
{
    public string Summarize(string documentText, int maxSentences)
    {
        if (string.IsNullOrWhiteSpace(documentText))
            return string.Empty;

        // Split into sentences using common delimiters
        var sentences = documentText
            .Split(['. ', '! ', '? '], StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .Where(s => !string.IsNullOrWhiteSpace(s))
            .ToArray();

        if (sentences.Length == 0)
            return documentText.Trim();

        // Score sentences by word frequency (extractive summarization)
        var wordFrequency = documentText
            .Split(' ', StringSplitOptions.RemoveEmptyEntries)
            .Select(w => w.ToLowerInvariant().Trim('.', ',', '!', '?', ';', ':'))
            .Where(w => w.Length > 3)
            .GroupBy(w => w)
            .ToDictionary(g => g.Key, g => g.Count());

        var scoredSentences = sentences
            .Select((sentence, index) => new
            {
                Text = sentence,
                Index = index,
                Score = sentence
                    .Split(' ', StringSplitOptions.RemoveEmptyEntries)
                    .Select(w => w.ToLowerInvariant().Trim('.', ',', '!', '?', ';', ':'))
                    .Where(w => wordFrequency.ContainsKey(w))
                    .Sum(w => wordFrequency[w])
            })
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .OrderBy(s => s.Index)
            .Select(s => s.Text.TrimEnd('.') + ".")
            .ToList();

        return string.Join(" ", scoredSentences);
    }
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly IDocumentSummarizer _summarizer;

    public SummarizeController(IDocumentSummarizer summarizer)
    {
        _summarizer = summarizer;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.DocumentText))
            return BadRequest("DocumentText is required.");

        var summary = _summarizer.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.DocumentText.Length,
            SummaryLength = summary.Length
        });
    }
}

